-- SafePlate demo data seed (with holder photos). Run in the Supabase SQL editor
-- AFTER schema.sql and schema_hardened.sql. Run ONCE (audit/notification/release rows
-- would duplicate on re-run). The SQL editor bypasses RLS, so inserts always apply.

alter table certificates add column if not exists cert_no text;
alter table certificates add column if not exists photo text;
alter table food_handlers add column if not exists lga text;
alter table food_handlers add column if not exists photo text;
alter table businesses add column if not exists owner_uid uuid;

on conflict (id) do nothing;

on conflict (safeplate_id) do update set photo = excluded.photo;

on conflict do nothing;

on conflict (safeplate_id) do update set photo = excluded.photo, cert_no = excluded.cert_no;

on conflict do nothing;

;

on conflict do nothing;

on conflict do nothing;

;

;

on conflict (owner_email) do nothing;

